export default function Forbidden() {
  const navigate = useNavigate();

  return (
    <Result
      icon={
        <div>
          <Icon />
        </div>
      }
      title='无权限'
      subTitle={
        <span style={{ color: '#f5222d' }}>警告: 您正在进行非法操作</span>
      }
      extra={[
        <Button
          key='home'
          type='primary'
          onClick={() => navigate('/', { replace: true })}
        >
          返回首页
        </Button>,
      ]}
    />
  );
}
